"use client";
import React, { Fragment, useState, useMemo } from "react";
import Image from "next/image";
import LessonItem from "@/components/lesson/lesson-item";
import { useParams, useRouter, useSearchParams } from "next/navigation";
import { WEEKLY_LESSONS, LESSONS_BY_GRADE, findLessonByIdGlobal } from "@/mock/data";
import { getUnitLessonsByGradeAndSlug, getUnitTitleByGradeAndSlug } from "@/mock/unit-lessons";

function UnitPage() {
  const router = useRouter();
  const params = useParams();
  const searchParams = useSearchParams();

  const lessonParams = searchParams.get("lesson");

  // Get grade from multiple sources with priority:
  // 1. Query params (?grade=X) - from navigation
  // 2. Route params ([grade]) - from URL path
  // 3. Parse from pathname
  // 4. Default to 5
  const gradeFromQuery = searchParams.get("grade");
  const pathname = typeof window !== 'undefined' ? window.location.pathname : '';
  const gradeMatch = pathname.match(/tieng-anh-lop-(\d+)/);
  const gradeFromPath = gradeMatch ? Number(gradeMatch[1]) : null;
  const gradeFromRoute = params.grade ? Number(params.grade) : gradeFromPath;
  
  // Priority: query params > route params > default
  const currentGrade = gradeFromQuery ? Number(gradeFromQuery) : (gradeFromRoute || 5);

  // Get slug from params
  const slug = params.slug as string || 'unit-1';

  // Get unit lessons dynamically based on grade and slug
  const UnitData = useMemo(() => {
    return getUnitLessonsByGradeAndSlug(currentGrade, slug);
  }, [currentGrade, slug]);

  // Get unit title dynamically
  const unitTitle = useMemo(() => {
    return getUnitTitleByGradeAndSlug(currentGrade, slug);
  }, [currentGrade, slug]);

  const [isSliding, setIsSliding] = useState(false);
  const [initialSliding, setInitialSliding] = useState(false);

  // Find the lesson from LESSONS_BY_GRADE based on lessonParams ID
  const currentLesson = React.useMemo(() => {
    if (!lessonParams) return null;

    // Use global search to find lesson across all grades
    const result = findLessonByIdGlobal(lessonParams);
    return result?.lesson || null;
  }, [lessonParams]);

  // If we have a selected lesson, create a display list with just that lesson, otherwise use UnitData
  const displayList = currentLesson
    ? [{
      ...UnitData[0], // Keep structure/mock stats from UnitData[0] for layout compatibility
      title: currentLesson.title,
      image: currentLesson.image,
      category_title: currentLesson.category_title,
      lessonDetails: currentLesson.lessonDetails // Pass lesson details from mock data
    }]
    : UnitData;

  const handleLessonClick = () => {
    if (!lessonParams) {
      setIsSliding(true);
    } else {
      router.push(`/lop-hoc?grade=${currentGrade}`)
    }
  };

  const handleBackClick = () => {
    if (lessonParams) {
      router.push(`/lop-hoc?grade=${currentGrade}`)
    } else if (!isSliding) {
      router.push(`/main/khoa-hoc/tieng-anh-lop-${currentGrade}`);
    } else {
      setIsSliding(false);
    }
  };

  return (
    <div className="bg-[url('/player_background.png')] w-screen h-screen bg-repeat bg-[length:560px_560px]">
      <div className="px-2 md:px-0 md:container pt-6 pb-1">
        <div className="cursor-pointer w-fit" onClick={handleBackClick}>
          <svg width="61" height="61" viewBox="0 0 61 61" fill="none" xmlns="http://www.w3.org/2000/svg" xmlnsXlink="http://www.w3.org/1999/xlink">
            <rect width="61" height="61" fill="url(#pattern0_274_77)" />
            <defs>
              <pattern id="pattern0_274_77" patternContentUnits="objectBoundingBox" width="1" height="1">
                <use xlinkHref="#image0_274_77" transform="scale(0.00195312)" />
              </pattern>
              <image id="image0_274_77" width="512" height="512" preserveAspectRatio="none" xlinkHref="data:image/png;base64," />
            </defs>
          </svg>


        </div>
        <div
          className={`shadow-md  ${isSliding ? "p-0" : "py-5"
            } rounded-2xl bg-[#f5fcff] lg:w-5/6 mx-auto h-[750px] relative overflow-hidden`}
        >
          <div
            className={`w-full h-full ${isSliding ? "animate-slideLeft" : "animate-slideRight px-3"
              }`}
          >
            {!lessonParams && (
              <h2 className="text-2xl font-semibold text-zinc-700 mb-3 lg:mb-12 ml-7">
                {unitTitle}
              </h2>
            )}

            {displayList.map((item, index) => {
              return (
                <Fragment key={index}>
                  <LessonItem
                    title={item.title}
                    image={item.image}
                    point={item.point}
                    rate={item.rate}
                    lessonInfo={item.lessonInfo}
                    onClick={handleLessonClick}
                    params={lessonParams}
                    categoryTitle={'category_title' in item ? item.category_title : ('categoryTitle' in item ? item.categoryTitle : undefined)}
                    lessonDetails={'lessonDetails' in item ? item.lessonDetails : undefined}
                  />
                </Fragment>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

export default UnitPage;
